var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"아직도 반격할 기운이 남아 있나 본데…….","JPN":"まだ反撃する元気が残っているみたいだけど……","ENG":"You still want to fight?","TWN":"還有力氣反擊嗎……"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"꽤 근성 있는 녀석이잖아, 너! 마음에 들어!","JPN":"中々根性あるじゃない！　気に入った！","ENG":"You have some backbone, I like that!","TWN":"你這傢伙很難纏嘛！我喜歡！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>손상 부위 수리 중. 교전 가능.</color>","JPN":"<color=#ff3636>損傷部位を修理中。交戦可能。</color>","ENG":"<color=#ff3636>Repairing damage. Ready to engage.</color>","TWN":"<color=#ff3636>正在修理損傷部位。可交戰。</color>"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_33"},{"id":"L6_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>대인 살상 용도로 주무장…… 교……교교…….</color>","JPN":"<color=#ff3636>対人殺傷用途に主武装……こう、こ、こ……</color>","ENG":"<color=#ff3636>Changing to anti-personnel weapon load... d... d...</color>","TWN":"<color=#ff3636>更換主要武器，目的是…殺…殺……殺…</color>  "},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L7_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"어? 왜 갑자기 머뭇거리지?","JPN":"あれ？　なぜ急にためらうの？","ENG":"Huh? Why is it stuttering?","TWN":"嗯？怎麼突然大舌頭？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"응! 나쁜 병에 걸린 것 같아서 내가 살짝 고쳐 줬어!","JPN":"うん！　悪い病気にかかってたみたいだから、私がちょっと直してあげたの！","ENG":"It’s me! I fixed it because it looked sick!","TWN":"嗯！我看它被病毒感染，所以有幫它清毒一下。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"굉장한데?! 멀대보다 유능하잖아, 너!","JPN":"すごいね！　ヒョロガリより有能じゃない！","ENG":"That’s great! You’re much better than Beanstalk!","TWN":"不錯喔？比傻大個還行呢！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>의료 시스템, 재%$#기동 실패.</color>","JPN":"<color=#ff3636>医療システム、再％$#起動失敗。</color>","ENG":"<color=#ff3636>Medical system re%$#activation failed.</color>","TWN":"<color=#ff3636>醫療系統，再%$#啟動失敗。</color>"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>운영체제에 치명적인 간섭 확인. 섬멸 태세로 변경.</color>","JPN":"<color=#ff3636>オペレーティングシステムに致命的な干渉を確認。殲滅態勢に変更。</color>","ENG":"<color=#ff3636>A critical interruption detected in the OS. Switching to Elimination mode.</color>","TWN":"<color=#ff3636>發現到對作業系統有致命性操作。變更為殲滅狀態。</color>"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"앗, 아깝다.","JPN":"あっ、惜しい。","ENG":"Ah, bummer.","TWN":"哎呀，真可惜。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"조금만 더 하면 정신을 차릴 수 있을 것 같았는데……. 병이 너무 심한가 봐.","JPN":"もう少しで正気に戻せると思ったのに……病気がひどいみたい。","ENG":"I almost cured it... but I guess its sickness ran too deep.","TWN":"我以爲再加點油就可以醫好它……看來它已經無藥可救。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"호오, 그럼 여태까지 이 이수연님을 상대로 진짜 실력을 숨기고 있었다?","JPN":"へえ、それじゃあ今までこのカナミ・キズナ様を相手に本当の実力を隠していたってこと？","ENG":"So you were holding back when you were fighting me?","TWN":"哦，你從剛剛就一直深藏不露呢？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"그렇다면 나도 질 수 없지!","JPN":"なら負けてられない！","ENG":"Okay, then!","TWN":"那麼我也不能輸！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"간다! 이것이 바로 스승님과의 뜨거운 훈련으로 완성한 필! 살! 기!","JPN":"行くよ！　これが師匠との熱い訓練で完成した必！　殺！　技！","ENG":"Behold! The ultimate skill that I’ve been training with the Master!","TWN":"看好！這就是在師父嚴格訓練子下完成的必！殺！技！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"오오, 필살기! 두근두근해~!","JPN":"おお、必殺技！　ワクワク！","ENG":"Oh, the ultimate skill! This is so exciting!","TWN":"哦哦，必殺技欸！好緊張～！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"당장 멈춰! 필살기 따위 세상에 존재하지 않아! 그딴 거 인정 못 해!","JPN":"今すぐやめなさい！　その必殺技はこの世に存在しないから！　そんなの認めない！","ENG":"Stop! There is no such thing as an ultimate skill! Oh, I can’t watch this!","TWN":"馬上停下來！世界上沒什麼必殺技！我不承認！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_CAR_SKID"},{"id":"L25_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"필───살───!","JPN":"必───殺───！","ENG":"Here comes a FATAL BLOW!!!","TWN":"必───殺───！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SKILL"},"R":null}},"sfx":"FX_COMBAT_ONLY_LEE_SUYEON_HYPER_ATTACK"},{"id":"L26_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"이수여어어어어어언!!","JPN":"カナミイイィィィィィ・キズナアアァァァァァ！！","ENG":"Lee Sooyeooooooooooooooooon!","TWN":"李秀妍！！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"스트라이크으으으으으!!!!","JPN":"ストライクゥゥゥゥゥゥゥゥ！！","ENG":"Striiiiiiiiiiiiiiiiiiiiiiiiike!","TWN":"爆斬！！！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SKILL"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>손상 부위── 수리 불──가.</color>","JPN":"<color=#ff3636>損傷部位── 修理不──可。</color>","ENG":"<color=#ff3636>Damage... beyond repair...</color>","TWN":"<color=#ff3636>損傷部位── 無法──修復。</color>"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"보았느냐, 느꼈느냐. 어리석은 침식체 녀석아.","JPN":"見たか！　感じたか！　この愚かな侵食体め。","ENG":"See that? You foolish Corrupted Object.","TWN":"看到了嗎，感受到了嗎，愚蠢的侵蝕體？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"이것이 바로 관리국 S급 카운터! 이수연 님의 힘인 것이다!","JPN":"これぞ管理局S級カウンター、カナミ・キズナ様の力だ！","ENG":"You just got whooped by the Grade S Counter of the Administration! The one and only, Lee Sooyeon!","TWN":"這就是管理局的S級制裁者，李秀妍大人的力量！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"우와아……. 바다가 갈라졌네.","JPN":"うわあ……海が割れた。","ENG":"Wow... she split the sea.","TWN":"哇賽……海裂開咧？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네! 모네!","JPN":"モネ！　モネ！","ENG":"Mone! Mone!","TWN":"莫妮！莫妮！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L45_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네에~","JPN":"モネネ～","ENG":"Monee!","TWN":"莫妮妮～"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L46_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네네! 모네모네!","JPN":"モネネ！　モネモネ！","ENG":"Monene! Mone Mone!","TWN":"莫妮妮！莫妮莫妮！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L49_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"어? 부사장님, 얼굴이 왜 그렇게 빨개? 어디 아파?","JPN":"あれ、副社長どうしたの？　顔が真っ赤だよ？　どっか痛いの？","ENG":"Huh? Vice President? Your face is all red. Do you have fever?","TWN":"嗯？副總臉怎麼這麼紅？不舒服嗎？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"어, 우리 딸. 부사장은 잠시 혼자 있게 두자꾸나.","JPN":"娘よ、副社長はしばらく一人にしてあげよう。","ENG":"My daughter. Let’s leave the Vice President alone for a while.","TWN":"女兒，讓副總一個人靜一靜吧。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"지금 부사장은 마음이 많이 아야 하고 있어요.","JPN":"今の副社長はね、心がイタイイタイしているんだ。","ENG":"She is not well at the moment.","TWN":"現在副總心裡有點五味雜陳。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"정말? 부사장님도 내가 호 해 줄까?","JPN":"本当に？　副社長も私が「痛いの痛いの飛んでけー」してあげよっか？","ENG":"Really? Do you want me to hug you?","TWN":"真的嗎？那我去給副總呼呼？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"……부탁이니까 둘 다 아무 말도 하지 마세요. 부녀 쌍으로 고철상에 팔아넘기기 전에.","JPN":"……お願いだから二人とも何も言わないでください。親子まとめて屑鉄屋に売り渡す前に。","ENG":"... Please, stop. Both of you. Or I’ll scrap you and toss the remains in the trash.","TWN":"……拜託你們兩個人都不要說話，否則我就把你們父女賣給收破爛的。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"누구야, 저 얼간이는……? S급 중에 저런 애가 있다는 말은 들은 적도 없는데……?","JPN":"なんだ、あのマヌケは……？　S級にあんなやつがいるなんて噂は聞いたことないけど……？","ENG":"Who is that idiot? I’ve never heard of that Grade S Counter.","TWN":"那個阿呆是誰啊……？我沒聽說過S級中有那樣的人啊……?"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"못된 언니! 여기 계셨슴까!","JPN":"悪いお姉さん！　ここにいたっすか！","ENG":"Mean lady, here you are!","TWN":"壞姊姊！原來你在這裡！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"촌뜨기 꼬맹이…….","JPN":"田舎者のガキ……","ENG":"Lame kid...","TWN":"老包子小鬼…"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"쳇. 무슨 재주로 저런 괴물들을 불러들였는지 몰라도, 기뻐하기엔 아직 이를걸.","JPN":"ちぇっ。どんな小細工であんな化け物を呼び出したのかわからないけど、喜ぶにはまだ早いだろ。","ENG":"Hmpf, I don’t now where you got those monsters, but it’s not over yet.","TWN":"嗟，我不知道你從哪找來這些怪胎，不過現在高興還太早！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"우리 의뢰주가 아직 멀쩡하게 살아 있으니까.","JPN":"うちの依頼主はまだ元気に生きているから。","ENG":"Our client is still intact.","TWN":"我們的委託人還健在好嗎！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"이번엔 운 좋게 넘어갔다고 쳐. 저 녀석들이 떠나면 어쩔 건데.","JPN":"今回は運良く乗り越えたとして。あいつらが去っていった後はどうするんだ。","ENG":"Even if you get away this time, what will you do when your friends are gone?","TWN":"這次算你們運氣好，但那些怪胎離開後呢？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하긴, 리조트가 기상조절 시스템에 대해 모른 척하면 관리국이 개입해도 조사하는 데 한참 걸리겠군.","JPN":"まあ、リゾートの方が気象調節システムについて知らないふりをすれば、管理局が介入しても調査はかなり時間がかかるだろうな。","ENG":"That’s true. If the resort denies their connection to the Weather Control System, the investigation won’t end in time, even with the Administration.","TWN":"也是，度假村假裝對氣象調節系統不知情的話，即使管理局介入，調查也需要很長的時間。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"그, 그러면…….","JPN":"じゃ……じゃあ……","ENG":"Th-then...","TWN":"那…那…"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"왜? 용병들이 항복했으니까 다 끝난 거 아냐?","JPN":"なぜだ？　傭兵が降参したから終わったんじゃないのか？","ENG":"What’s the matter? The mercenaries surrendered. It’s over, right?","TWN":"為什麼？傭兵不是都已經舉白旗投降嗎？還沒結束喔？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"어머, 그것도 모르고 용병들이 있는 데 뛰어들었던 거예요?","JPN":"あら、それも知らずに傭兵のアジトに飛び込んだのですか？","ENG":"What, you just jumped in without understanding the situation?","TWN":"哎呀，你連事情都沒搞清楚就跳進來喔？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"훗훗훗. 구조대원이라면 사람을 구하는 일에 물불 가리지 말아야지.","JPN":"フッフッフッ、救助隊員なら人を救うことに水や火も辞さないべきだろ。","ENG":"Hah hah. That’s what a rescue worker does. Help people in need, regardless of the situation.","TWN":"呵呵呵，救難隊員沒有在挑工作的。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"펭귄 떼는 쬐, 쬐끔 무서웠지만.","JPN":"ペンギンの群れは、ちょ、ちょっとだけ怖かったけど。","ENG":"W-well, the penguins were a bit scary, though.","TWN":"雖然我是有點怕企鵝啦。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"글쎄, 저~기 있는 리조트가 이 마을을 없애 버리고 싶어한대요.","JPN":"あそこにあるリゾートがこの村をなくしたいそうです。","ENG":"You see, the resort over there wants to get rid of this village.","TWN":"是喔，我是聽說那～邊的度假村想消滅這個村莊。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"참 못된 사람들이라니까요. 전 아직 장사는커녕 개업도 못 했는데~","JPN":"本当に悪い人たちですよ。私はまだ商売どころか開業もしてないのに。","ENG":"They are so mean. I haven’t even started my business here yet.","TWN":"他們真的很壞欸！害我都做不成生意～"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"마을을 없애? 그럼 내 대활약을 회상할 장소도 사라진다는 거 아냐?","JPN":"村をなくす？　じゃあ、私の大活躍を回想する場所も消えるってことか？","ENG":"Get rid of this village? But this is the place where I can reminiscence my heroic deed!","TWN":"消滅村莊？所以我剛大展身手的地方也會消失不見囉？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"응, 아빠! 나야, 린 시엔!","JPN":"もしもし、パパ？　リン・シエンだよ！","ENG":"Hello, dad! Yes, it’s me, Lin Xien!","TWN":"喂，爸爸！是我，林·西恩！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"있지, 나 올해 생일 선물 안 받았잖아? 그거 오늘 미리 받으면 안 돼?","JPN":"あのね、今年の私の誕生日プレゼントってまだでしょ？　それって今日もらっちゃダメ？","ENG":"I didn’t get my birthday present yet, right? Can I have it today?","TWN":"那個，我今年還沒收到生日禮物吧？我想要預支？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"응, 응. 리조트 하나만. 그러니까 위치가 어디냐면…….","JPN":"うん、うん。リゾート一つだけ。えっと、場所はね……","ENG":"Yes, yes. I want a resort. It’s located in...","TWN":"嗯，嗯，只要一個度假村就好。地址在…"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"아, 정말?","JPN":"え、本当に？","ENG":"Oh, really?","TWN":"喔，真的嗎？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"사랑해, 아빠! 대신 아빠 말대로 연말엔 잠깐 가출 휴식할게!","JPN":"ありがと、大好きだよ、パパ！　代わりにパパの言うこと聞いて、年末の家出は休むから！","ENG":"I love you, dad! Okay, I’ll stop running away from home over the holidays, just as you asked!","TWN":"爸爸我愛你！就照爸爸的意思，離家出走會在年底先暫停一下！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"자, 이제 마을을 건드릴 사람은 없을 거야.","JPN":"さあ、これで村人をいじめる人はいなくなったはずだ。","ENG":"There, no one will mess with your village now.","TWN":"好了，現在沒有人敢碰這個村莊了。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"없기는 뭐가 없어! 장난하냐?!","JPN":"いなくなった？　ふざけてんの！？","ENG":"What do you mean, no one? Are you kidding me?!","TWN":"什麼不敢！你在胡說什麼？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"이것 봐. 말 끝나자마자 의뢰주한테서 문자 왔잖아.","JPN":"ほら。話が終わった途端、依頼主からメールが届いたじゃん。","ENG":"Look, the client texted me just now.","TWN":"你看，說曹操曹操到，委託人傳簡訊來！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"<color=#ffd34c>핵심 주주께서 마을 철거를 중단하라고 하셔서 이번 의뢰는 취소했습니다.</color>","JPN":"<color=#ffd34c>大株主から村の撤去を中断するようにと言われたので、今回の依頼は取り消しました。</color>","ENG":"<color=#ffd34c>Our main shareholder requested us to stop evicting the village. So we’re canceling the request.</color>","TWN":"<color=#ffd34c>由於大股東要求停止拆除村子，因此取消此次委託。</color>"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"<color=#ffd34c>선금은 반환 요구하지 않을 테니 여기서 조용히 끝냅시다…….</color>","JPN":"<color=#ffd34c>前金は返還要求しませんので、話はこれで終わりにしましょう……</color>","ENG":"<color=#ffd34c>We won’t ask you to return the down payment. Let’s just wrap it up without further ado...</color>","TWN":"<color=#ffd34c>我不會要求退還訂金，這件事就到此為止吧…</color>"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"……엉?","JPN":"……えっ？","ENG":"... Huh?","TWN":"…嗯？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"훗훗훗. 이걸로 욕망의 소용돌이에서 마을을 또 한 번 구해 버렸군.","JPN":"フッフッフッ。これで欲望の渦から村をもう一度救ってしまったな。","ENG":"Hah hah. Once again, I saved the village from the flames of desire.","TWN":"呵呵呵，我又再次救村莊脫離貪婪之手囉。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"역시 주인님! 처음부터 진짜 해결사를 데려오셨지 말임다!","JPN":"さすがご主人様！　最初から本物のフィクサーを連れてきてくれたんっすね！","ENG":"Wow! You really had a true fixer with you all along, Master!","TWN":"真不愧是主人！真的邀請到問題終結者欸！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하. 하. 하. 그, 그렇고 말고 모네 양.","JPN":"ハ、ハ、ハ。そ、そうだともモネ。","ENG":"Ha... Hah hah... Of course I did, Mone...","TWN":"哈，哈，哈，別這麼說。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"……이런 해결책은 전혀 고려하지 않았네만.","JPN":"……こんな解決策はまったく考慮していなかったが。","ENG":"... Although this is not what I expected.","TWN":"…我可沒想過這種解決方案呢。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그러니까, 네 아빠가 물주라 말 한마디에 쟤들이 깨갱했다고?","JPN":"で、お前のパパがお金持ちで、電話一本入れたらあいつらが尻尾巻いて逃げたって？","ENG":"So they are stepping down, because your dad holds the pursestrings?","TWN":"意思就是你爸爸是大股東，只要他說一句，其他人都要乖乖聽話？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"야, 이 멍청아! 처음부터 말했으면 이딴 생고생할 필요도 없었잖아!","JPN":"バカじゃないの？　最初からそうすればこんな苦労する必要もなかったじゃない！","ENG":"Why didn’t you say so, you idiot? We could have avoided all this!","TWN":"喂，你這個傻瓜！為什麼不一開始就說，害我們那麼辛苦！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L4_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"헤헷. 그래도 다친 사람은 없지 말임다.","JPN":"ヘヘッ、それでも怪我人が出なくてよかったっす。","ENG":"Heh heh. But no one’s hurt, ma’am.","TWN":"嘿嘿，至少沒有人受傷嘛。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"일어나십셔. 나쁜 언니. 모네가 도와 드리겠슴다.","JPN":"立ってください、悪いお姉さん。モネが手を貸してあげるっす。","ENG":"Stand up, mean lady. Mone will help you.","TWN":"起來吧，壞姊姊。莫妮拉你一把。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"너 호구냐? 나한테 잔뜩 시달렸던 주제에 뭘 좋다고 손을 내밀어?","JPN":"お前はバカなの？　あたしに散々言われてやられて、プライドもないわけ？","ENG":"Are you a moron? I tortured you and your family, yet you’re trying to help me?","TWN":"你是笨蛋嗎？被我折騰那麼久，還伸手幫我？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"해적 언니랑 저기 아저씨들은 토네이도가 걱정돼서 그런 거 아니셨슴까.","JPN":"海賊のお姉さんとあそこにいるおじさんたちは、トルネードを使われるのが心配であんなことをしたっすよね。","ENG":"I understand now that you and those men were worried about the tornado.","TWN":"海盜姊姊和那些大叔不是也很擔心龍捲風嗎？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"이제 전부 해결됐으니까, 사이 좋게 지내면 되지 말임다!","JPN":"もうすべて解決したし、これからは仲良くすればいいと思うっすよ？","ENG":"It’s all good now, so let’s just be nice to each other, ma’am!","TWN":"現在都解決了，以後就好好相處吧！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"너 평소에도 바보란 소리 자주 듣지?","JPN":"お前さ、普段からバカってよく言われるだろ？","ENG":"People call you an idiot, don’t they?","TWN":"平常應該也很多人說你是笨蛋吧？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"모, 모네 바보 아님다!","JPN":"モ、モネはバカじゃないっす！","ENG":"M-Mone is not an idiot!","TWN":"莫…莫妮不笨！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"하아. 이런 알기 쉬운 바보들 때문에 내 경력에 흠이 가네.","JPN":"はあ、こんなわかりやすいバカたちのせいであたしの経歴に傷がつくなんて。","ENG":"Oh... You idiots are hurting my career...","TWN":"哀，都是這些笨蛋會害我的履歷有瑕疵！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"어차피 프론트 베이로 가는 배는 내일이나 올 거야.","JPN":"どうせフロントベイに行く船は明日にならないと来ない。","ENG":"The ship to Front Bay will come tomorrow.","TWN":"反正去前灣的船明天才會來。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그러니 여기서…… 딱 하루만 묵지, 뭐.","JPN":"だからここで……一日だけ泊まってやる。","ENG":"So I’ll just stay here... for a day.","TWN":"所以就在這裡…住一天吧！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"이틀 지내셔도 끄떡없슴다!","JPN":"二日泊まっても大丈夫っすよ！","ENG":"Or two, ma’am!","TWN":"住兩天也沒問題的唷！"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};